import React from 'react';
import { View, Text } from 'react-native';
import PaymentModule from './PaymentModule';

class InAppPurchase extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
      isLoading: false,
      purchaseStatus: null,
    };
  }

  handlePurchase = async () => {
    try {
      this.setState({ isLoading: true });
      const response = await PaymentModule.purchaseProduct(this.props.productId);
      if (response.status === 'success') {
        this.setState({ purchaseStatus: 'success' });
      } else {
        this.setState({ purchaseStatus: 'failure' });
      }
    } catch (error) {
      console.log(error);
      this.setState({ purchaseStatus: 'failure' });
    } finally {
      this.setState({ isLoading: false });
    }
  };

  render() {
    return (
      <View>
        <Text>In-App Purchase</Text>
        <Button onPress={this.handlePurchase} title="Buy" />
        {this.state.isLoading && <ActivityIndicator size="large" color="#0000ff" />}
        {this.state.purchaseStatus === 'success' && (
          <Text>Purchase successful!</Text>
        )}
        {this.state.purchaseStatus === 'failure' && (
          <Text>Purchase failed!</Text>
        )}
      </View>
    );
  }
}